#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int isMagical(int* A, int N, int i) {
    int visited[N];
    for (int j = 0; j < N; j++) visited[j] = 0;
    int curr = i;
    while (!visited[curr]) {
        visited[curr] = 1;
        curr = (curr + A[curr] + 1) % N;
    }
    return visited[curr] == 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) scanf("%d", &A[i]);
        int count = 0;
        for (int i = 0; i < N; i++) {
            if (isMagical(A, N, i)) count++;
        }
        printf("%d\n", count);
        free(A);
    }
    return 0;
}

