import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static boolean isMagical(int[] A, int i) {
        boolean[] visited = new boolean[A.length];
        int curr = i;
        while (!visited[curr]) {
            visited[curr] = true;
            curr = (curr + A[curr] + 1) % A.length;
        }
        return visited[curr];
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) A[i] = sc.nextInt();
            int count = 0;
            for (int i = 0; i < N; i++) {
                if (isMagical(A, i)) count++;
            }
            System.out.println(count);
        }
    }
}

