    if b == 0: return a
    return gcd(b, a % b)

def isMagical(A, i):
    visited = [False] * len(A)
    curr = i
    while not visited[curr]:
        visited[curr] = True
        curr = (curr + A[curr] + 1) % len(A)
    return visited[curr]

